checker_dsl:
EXISTS (`method call MC`, `expression SINK_EXPR`, `data flow node SOURCE_NODE`) {
  AND {
    EXISTS (`data flow node SINK_NODE`) {
      AND {
        OR {
          EXISTS (`method call MA`) {
            AND {
              (`MA is MC`),
              OR {
                AND {
                  (`MA's method is named "readObject"`),
                  (`MA's method's declaring type has ObjectInput as a supertype`),
                  (`SINK_EXPR is MA's qualifier`),
                  NOT {
                    EXISTS (`type T`) {
                      AND {
                        (`T is the type bound of the data flow node for SINK_EXPR`),
                        OR {
                          (`T has qualified name "org.apache.commons.io.serialization.ValidatingObjectInputStream"`),
                          (`T has qualified name "org.nibblesec.tools.SerialKiller"`)
                        }
                      }
                    }
                  }
                },
                AND {
                  (`MA's method is named "readUnshared"`),
                  (`MA's method's declaring type has ObjectInputStream as a supertype`),
                  (`SINK_EXPR is MA's qualifier`),
                  NOT {
                    EXISTS (`type T`) {
                      AND {
                        (`T is the type bound of the data flow node for SINK_EXPR`),
                        OR {
                          (`T has qualified name "org.apache.commons.io.serialization.ValidatingObjectInputStream"`),
                          (`T has qualified name "org.nibblesec.tools.SerialKiller"`)
                        }
                      }
                    }
                  }
                },
                AND {
                  (`MA's method is an XStreamReadObjectMethod`),
                  (`SINK_EXPR is an argument of MA`)
                },
                AND {
                  (`MA's method is a KryoReadObjectMethod`),
                  (`SINK_EXPR is an argument of MA`)
                },
                AND {
                  (`MA is an instance of UnsafeSnakeYamlParse`),
                  (`SINK_EXPR is MA's first argument`)
                },
                AND {
                  (`MA's method is a FastJsonParseMethod`),
                  (`SINK_EXPR is MA's first argument`)
                },
                AND {
                  (`MA's method is an ObjectMapperReadMethod`),
                  (`SINK_EXPR is MA's first argument`),
                  NOT { EXISTS (`safe flow condition`) { (`safe flow condition holds`) } }
                },
                AND {
                  (`MA's method is a JabsorbUnmarshallMethod`),
                  (`SINK_EXPR is MA's third argument`)
                },
                AND {
                  (`MA's method is a JoddJsonParseMethod`),
                  (`SINK_EXPR is MA's first argument`),
                  OR {
                    EXISTS (`expression PARSER_EXPR`) {
                      AND {
                        (`PARSER_EXPR is MA's qualifier`),
                        EXISTS (`data flow node PARSER_NODE`) {
                          AND {
                            (`PARSER_NODE's expression is PARSER_EXPR`)
                          }
                        }
                      }
                    }
                  }
                },
                AND {
                  (`MA's method is a FlexjsonDeserializeMethod`),
                  (`SINK_EXPR is MA's first argument`)
                },
                AND {
                  (`MA's method is a GsonDeserializeMethod`),
                  (`SINK_EXPR is MA's first argument`)
                },
                AND {
                  (`MA's method overrides (transitively) an ObjectMessageGetObjectMethod`),
                  (`SINK_EXPR is the underlying expression of MA's qualifier`),
                  NOT { EXISTS (`callable C`) { (`C is a viable callable for MA`) } }
                }
              }
            }
          }
        },
        OR {
          AND {
            (`SINK_EXPR is either MC's qualifier or an argument of MC`)
          }
        }
      }
    },
    (`there exists a taint flow path from SOURCE_NODE to SINK_NODE`),
    NOT {
      EXISTS (`data flow node BARRIER_NODE on the flow path`) {
        OR {
          EXISTS (`class instance expression CIE`) {
            AND {
              (`CIE's constructor's declaring type is JsonIoJsonReader`),
              (`CIE's expression equals BARRIER_NODE's expression`)
            }
          },
          EXISTS (`method call MA2`) {
            AND {
              (`MA2's method is a JsonIoJsonToJavaMethod`),
              (`BARRIER_NODE's expression equals MA2's first argument`)
            }
          },
          EXISTS (`method call MA3`) {
            AND {
              (`MA3's method is a JoddJsonParseMethod`),
              (`MA3's second argument's type is a TypeClass`),
              NOT { (`MA3's second argument is a NullLiteral`) },
              NOT { (`MA3's second argument's type name is "Class<Object>" or "Class<?>"`) },
              (`BARRIER_NODE's expression equals an argument of MA3`)
            }
          },
          EXISTS (`method call MA4`) {
            AND {
              (`MA4's method is a FlexjsonDeserializeMethod`),
              (`BARRIER_NODE's expression equals an argument of MA4`),
              OR {
                AND {
                  (`MA4's second argument's type is a TypeClass`),
                  NOT { (`MA4's second argument is a NullLiteral`) },
                  NOT { (`MA4's second argument's type name is "Class<Object>" or "Class<?>"`) }
                }
              }
            }
          }
        }
      }
    }
  }
}
